#!/usr/bin/env npx tsx
/**
 * STT (Whisper) Model Benchmark
 *
 * Benchmarks speech-to-text models on transcription accuracy, latency,
 * and word error rate using synthetic audio generated by Kokoro TTS.
 *
 * Usage:
 *   npx tsx tests/bench/run-stt-bench.ts              # run benchmark
 *   npx tsx tests/bench/run-stt-bench.ts --save        # persist results
 *   npx tsx tests/bench/run-stt-bench.ts --list        # show test phrases
 *
 * Metrics:
 *   - Word Error Rate (WER): edit distance between expected and transcribed words
 *   - Transcription speed: real-time factor (audio duration / transcription time)
 *   - Character Error Rate (CER): character-level accuracy
 *   - Latency: time to first transcription result
 */

import { writeFileSync, mkdirSync } from 'fs';
import { join } from 'path';

// ── Test phrases (ground truth for WER computation) ─────────────────────────

const TEST_PHRASES = [
  { id: 'short', text: 'Hello, I am Shelly the turtle.' },
  { id: 'medium', text: 'Your knowledge base has fifteen entities and forty-two confirmed triples across three sources.' },
  { id: 'long', text: 'I found a potential merge between the entities SvelteKit and Svelte Kit framework. They appear to refer to the same technology. Would you like me to combine them into a single node in your knowledge graph?' },
  { id: 'technical', text: 'The RDF triple extraction pipeline uses a quantized transformer model running in WebAssembly to convert unstructured text into subject predicate object statements.' },
  { id: 'conversational', text: "That's a great question! Based on your knowledge base, Reckons AI is built with SvelteKit and uses Dexie for local storage." },
];

const WHISPER_MODELS = [
  { id: 'onnx-community/whisper-tiny', label: 'Whisper Tiny', note: '~42 MB' },
];

// ── CLI ──────────────────────────────────────────────────────────────────────

const args = process.argv.slice(2);
const saveResults = args.includes('--save');

if (args.includes('--list')) {
  console.log('\nTest phrases (ground truth):');
  for (const p of TEST_PHRASES) {
    const words = p.text.split(/\s+/).length;
    console.log(`  ${p.id.padEnd(16)} ${words}w  "${p.text.slice(0, 60)}..."`);
  }
  console.log(`\nModels: ${WHISPER_MODELS.map(m => m.label).join(', ')}`);
  process.exit(0);
}

// ── WER / CER computation ───────────────────────────────────────────────────

function normalizeText(text: string): string {
  return text
    .toLowerCase()
    .replace(/[^\w\s]/g, '') // strip punctuation
    .replace(/\s+/g, ' ')
    .trim();
}

/** Levenshtein distance between two arrays */
function editDistance(a: string[], b: string[]): number {
  const m = a.length;
  const n = b.length;
  const dp: number[][] = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(0));

  for (let i = 0; i <= m; i++) dp[i][0] = i;
  for (let j = 0; j <= n; j++) dp[0][j] = j;

  for (let i = 1; i <= m; i++) {
    for (let j = 1; j <= n; j++) {
      if (a[i - 1] === b[j - 1]) {
        dp[i][j] = dp[i - 1][j - 1];
      } else {
        dp[i][j] = 1 + Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
      }
    }
  }

  return dp[m][n];
}

function computeWER(reference: string, hypothesis: string): number {
  const refWords = normalizeText(reference).split(' ').filter(Boolean);
  const hypWords = normalizeText(hypothesis).split(' ').filter(Boolean);
  if (refWords.length === 0) return hypWords.length === 0 ? 0 : 1;
  return editDistance(refWords, hypWords) / refWords.length;
}

function computeCER(reference: string, hypothesis: string): number {
  const refChars = normalizeText(reference).split('');
  const hypChars = normalizeText(hypothesis).split('');
  if (refChars.length === 0) return hypChars.length === 0 ? 0 : 1;
  return editDistance(refChars, hypChars) / refChars.length;
}

// ── Types ────────────────────────────────────────────────────────────────────

interface STTResult {
  phraseId: string;
  model: string;
  referenceText: string;
  transcribedText: string;
  wer: number;
  cer: number;
  transcriptionMs: number;
  audioDurationSec: number;
  realTimeFactor: number;
  success: boolean;
}

interface STTBenchReport {
  timestamp: string;
  ttsModel: string;
  results: STTResult[];
  summary: {
    model: string;
    loadTimeMs: number;
    avgWER: number;
    avgCER: number;
    avgTranscriptionMs: number;
    avgRealTimeFactor: number;
    successRate: number;
    totalPhrases: number;
  };
}

// ── Benchmark ────────────────────────────────────────────────────────────────

async function main() {
  console.log(`\n${'='.repeat(60)}`);
  console.log('  STT (WHISPER) MODEL BENCHMARK');
  console.log(`${'='.repeat(60)}`);
  console.log(`Phrases: ${TEST_PHRASES.length}`);
  console.log(`Models: ${WHISPER_MODELS.map(m => m.label).join(', ')}`);

  // Step 1: Generate reference audio using Kokoro TTS
  console.log('\nStep 1: Generating reference audio with Kokoro TTS...');
  let tts: any;
  try {
    const { KokoroTTS } = await import('kokoro-js');
    tts = await KokoroTTS.from_pretrained('onnx-community/Kokoro-82M-v1.0-ONNX', {
      dtype: 'q8',
      device: 'auto' as any,
    });
    console.log('  Kokoro TTS loaded.');
  } catch (e) {
    console.error(`  Failed to load Kokoro TTS: ${(e as Error).message}`);
    console.log('\n  Kokoro TTS is needed to generate test audio. Install: npm install kokoro-js');
    console.log('  Falling back to synthetic audio test...');
    tts = null;
  }

  // Generate audio for each phrase
  const audioSamples: Map<string, { audio: Float32Array; durationSec: number }> = new Map();

  if (tts) {
    for (const phrase of TEST_PHRASES) {
      try {
        const result = await tts.generate(phrase.text, { voice: 'af_heart' });
        if (result?.audio) {
          const samples = result.audio;
          const sampleCount = samples.length ?? 0;
          const durationSec = sampleCount / 24000; // Kokoro outputs at 24kHz
          // Resample from 24kHz to 16kHz for Whisper
          const resampled = resample24kTo16k(samples);
          audioSamples.set(phrase.id, { audio: resampled, durationSec });
          console.log(`  Generated: ${phrase.id} (${durationSec.toFixed(2)}s)`);
        }
      } catch (e) {
        console.warn(`  Failed to generate audio for ${phrase.id}: ${(e as Error).message}`);
      }
    }
  }

  if (audioSamples.size === 0) {
    // Create synthetic 16kHz silence as fallback (Whisper should return empty/noise)
    console.log('  Using synthetic silence as fallback audio (WER will be ~1.0)');
    for (const phrase of TEST_PHRASES) {
      const durationSec = 2.0;
      const samples = new Float32Array(16000 * durationSec); // silence
      audioSamples.set(phrase.id, { audio: samples, durationSec });
    }
  }

  // Step 2: Transcribe with each Whisper model
  for (const model of WHISPER_MODELS) {
    console.log(`\n${'─'.repeat(60)}`);
    console.log(`  MODEL: ${model.label} (${model.id})`);
    console.log(`${'─'.repeat(60)}`);

    console.log('  Loading Whisper model...');
    const loadStart = Date.now();

    let whisperPipeline: any;
    try {
      const { pipeline, env } = await import('@huggingface/transformers');
      env.cacheDir = join(process.env.HOME || '.', '.cache', 'huggingface');
      whisperPipeline = await pipeline('automatic-speech-recognition', model.id, {
        dtype: 'q8',
        device: 'cpu',
      });
    } catch (e) {
      console.error(`  SKIP: failed to load — ${(e as Error).message}`);
      continue;
    }

    const loadTimeMs = Date.now() - loadStart;
    console.log(`  Loaded in ${(loadTimeMs / 1000).toFixed(1)}s`);

    const results: STTResult[] = [];

    for (const phrase of TEST_PHRASES) {
      const sample = audioSamples.get(phrase.id);
      if (!sample) {
        console.log(`  \u2717 ${phrase.id.padEnd(16)} No audio available`);
        continue;
      }

      const transcribeStart = Date.now();
      let transcribedText = '';
      let success = false;

      try {
        const result = await whisperPipeline(sample.audio, {
          return_timestamps: true,
          language: 'en',
          chunk_length_s: 30,
        });
        transcribedText = (result.text ?? '').trim();
        success = transcribedText.length > 0;
      } catch (e) {
        console.log(`  \u2717 ${phrase.id.padEnd(16)} FAILED: ${(e as Error).message}`);
      }

      const transcriptionMs = Date.now() - transcribeStart;
      const wer = computeWER(phrase.text, transcribedText);
      const cer = computeCER(phrase.text, transcribedText);
      const rtf = sample.durationSec > 0 ? sample.durationSec / (transcriptionMs / 1000) : 0;

      const icon = success ? '\u2713' : '\u2717';
      console.log(`  ${icon} ${phrase.id.padEnd(16)} ${transcriptionMs}ms  WER=${(wer * 100).toFixed(1)}%  CER=${(cer * 100).toFixed(1)}%  RTF=${rtf.toFixed(2)}x`);
      if (transcribedText) {
        console.log(`    ref: "${phrase.text.slice(0, 70)}..."`);
        console.log(`    hyp: "${transcribedText.slice(0, 70)}..."`);
      }

      results.push({
        phraseId: phrase.id,
        model: model.id,
        referenceText: phrase.text,
        transcribedText,
        wer,
        cer,
        transcriptionMs,
        audioDurationSec: sample.durationSec,
        realTimeFactor: rtf,
        success,
      });
    }

    // Summary
    const successResults = results.filter(r => r.success);
    const avgWER = successResults.length > 0
      ? successResults.reduce((s, r) => s + r.wer, 0) / successResults.length : 1;
    const avgCER = successResults.length > 0
      ? successResults.reduce((s, r) => s + r.cer, 0) / successResults.length : 1;
    const avgMs = successResults.length > 0
      ? successResults.reduce((s, r) => s + r.transcriptionMs, 0) / successResults.length : 0;
    const avgRTF = successResults.length > 0
      ? successResults.reduce((s, r) => s + r.realTimeFactor, 0) / successResults.length : 0;

    console.log(`\n${'='.repeat(60)}`);
    console.log('  SUMMARY');
    console.log(`${'='.repeat(60)}`);
    console.log(`  Model load:       ${(loadTimeMs / 1000).toFixed(1)}s`);
    console.log(`  Avg WER:          ${(avgWER * 100).toFixed(1)}%`);
    console.log(`  Avg CER:          ${(avgCER * 100).toFixed(1)}%`);
    console.log(`  Avg transcription: ${avgMs.toFixed(0)}ms`);
    console.log(`  Avg RTF:          ${avgRTF.toFixed(2)}x real-time`);
    console.log(`  Success rate:     ${successResults.length}/${results.length}`);

    if (saveResults) {
      const report: STTBenchReport = {
        timestamp: new Date().toISOString(),
        ttsModel: tts ? 'onnx-community/Kokoro-82M-v1.0-ONNX' : 'synthetic-silence',
        results,
        summary: {
          model: model.id,
          loadTimeMs,
          avgWER: parseFloat((avgWER).toFixed(4)),
          avgCER: parseFloat((avgCER).toFixed(4)),
          avgTranscriptionMs: Math.round(avgMs),
          avgRealTimeFactor: parseFloat(avgRTF.toFixed(2)),
          successRate: successResults.length / results.length,
          totalPhrases: TEST_PHRASES.length,
        },
      };

      const dir = join(import.meta.dirname || __dirname, 'results');
      mkdirSync(dir, { recursive: true });
      const ts = new Date().toISOString().slice(0, 19).replace(/:/g, '-');
      const slug = model.id.replace(/\//g, '_');
      const filename = `stt-bench_${slug}_${ts}.json`;
      writeFileSync(join(dir, filename), JSON.stringify(report, null, 2));
      console.log(`\nResults saved to tests/bench/results/${filename}`);
    }

    // Dispose
    if (whisperPipeline?.dispose) {
      try { await whisperPipeline.dispose(); } catch { /* ignore */ }
    }
  }
}

/** Resample Float32Array from 24kHz to 16kHz using linear interpolation */
function resample24kTo16k(samples: Float32Array): Float32Array {
  const ratio = 24000 / 16000; // 1.5
  const outLength = Math.floor(samples.length / ratio);
  const out = new Float32Array(outLength);

  for (let i = 0; i < outLength; i++) {
    const srcIdx = i * ratio;
    const lo = Math.floor(srcIdx);
    const hi = Math.min(lo + 1, samples.length - 1);
    const frac = srcIdx - lo;
    out[i] = samples[lo] * (1 - frac) + samples[hi] * frac;
  }

  return out;
}

main().catch(e => {
  console.error('STT bench failed:', e);
  process.exit(1);
});
